import { isRowSelectedInTree } from "./is-row-selected-in-tree.js";
export function isRowSelected(id, s, getParents) {
    if (s.kind === "isolated") {
        const isInExceptions = s.exceptions.has(id);
        return s.selected ? !isInExceptions : isInExceptions;
    }
    const parents = getParents(id);
    parents.push(id);
    const result = isRowSelectedInTree(s.selected, s.children, parents);
    return result;
}
